1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type Step = { items: Item[] };
12	type Scenario = { steps: Step[] };
13	
14	export function processScenario(scenario: unknown): unknown {
15	  const { steps } = scenario as Scenario;
16	  const items = steps[0].items;
17	  const basePremium = items.reduce(
18	    (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
19	    0,
20	  );
21	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
22	}
